using Starling.Css.Values;

namespace Starling.Css.Spec.Tests.CssColor;

/// <summary>
/// Property conformance for <see href="https://drafts.csswg.org/css-color-4/">CSS Color Module Level 4</see>.
/// </summary>
[TestClass]
[Spec("css-color", "https://drafts.csswg.org/css-color-4/")]
public sealed class PropertyTests
{
    private static CssValue ParseSingle(string property, string value)
    {
        var sheet = CssParser.ParseStyleSheet($"a{{{property}:{value}}}");
        var rule = (StyleRule)sheet.Rules.Single();
        var decl = rule.Declarations.Single();
        decl.Name.Should().Be(property);
        return CssValueParser.Parse(decl.Value);
    }

    /// <summary>Spec: <see href="https://drafts.csswg.org/css-color-4/#propdef-color"/>
    /// <para>Property <c>color</c> — value <c>&lt;color&gt;</c>; initial <c>CanvasText</c>.</para>
    /// <para>Strict: the value parser produces a typed <see cref="Starling.Css.Values.CssColor"/>
    /// for the named-color, 8-bit hex, and modern <c>rgb()</c> syntaxes, with the
    /// spec-mandated R/G/B/A bytes.</para>
    /// </summary>
    [Spec("css-color", "https://drafts.csswg.org/css-color-4/#propdef-color")]
    [SpecFact]
    public void Parses_color()
    {
        ParseSingle("color", "red").Should().BeEquivalentTo(new { R = (byte)255, G = (byte)0,   B = (byte)0,   A = (byte)255 });
        ParseSingle("color", "#00ff00").Should().BeEquivalentTo(new { R = (byte)0,   G = (byte)255, B = (byte)0,   A = (byte)255 });
        ParseSingle("color", "rgb(0 0 255)").Should().BeEquivalentTo(new { R = (byte)0,   G = (byte)0,   B = (byte)255, A = (byte)255 });
    }

