    /// <para>Strict: the value parser produces a typed <c>CssNumber</c> for unit-less
    /// values and a typed <c>CssPercentage</c> for percentages, with the literal magnitude.</para>
    /// </summary>
    [Spec("css-color", "https://drafts.csswg.org/css-color-4/#propdef-opacity")]
    [SpecFact]
    public void Parses_opacity()
